from django import template# from ..models import Comment,Postfrom blog.models import Comment, Postregister = template.Library()@register.simple_tag()def total_comment():    return Comment.objects.filter(active=True).count()@register.simple_tag()def total_post():    return Post.published.count()@register.simple_tag()def last_post_date():    return Post.published.last()@register.inclusion_tag("partials/latest_post.html")def latest_post(count=4):    l_post = Post.published.order_by('-publish')[:count]    context = {        'l_post':l_post    }    return context